input.command:
# Find every .claude directory on C: and G: (transcripts live under .claude\projects)
$roots = @('C:\','G:\')
$found = foreach ($r in $roots) {
  Get-ChildItem -Path $r -Directory -Recurse -Filter '.claude' -ErrorAction SilentlyContinue -Force
}
$found | ForEach-Object {
  $proj = Join-Path $_.FullName 'projects'
  $count = 0
  if (Test-Path $proj) { $count = (Get-ChildItem $proj -Recurse -Filter *.jsonl -File -ErrorAction SilentlyContinue | Measure-Object).Count }
  [PSCustomObject]@{ ClaudeDir = $_.FullName; Transcripts = $count }
} | Sort-Object Transcripts -Descending | Format-Table -AutoSize

